class Solution {
    public int maxVowels(String s, int k) {
        int count = 0;
        for (int i = 0; i < s.length(); i++) {
            for (int j = i + 1; j < i + k && j < s.length(); j++) {
                char c1 = s.charAt(i);
                char c2 = s.charAt(j);
                if (isVowel(c1) && isVowel(c2)) {
                    count++;
                }
            }
        }
        return count;
    }

    private boolean isVowel(char c) {
        return c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u';
    }
}
